import { readFile, writeFile } from "node:fs/promises";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const packageDir = path.resolve(__dirname, "..");
const repoRoot = path.resolve(packageDir, "..", "..");
const srcDir = path.join(packageDir, "src");
const indexPath = path.join(srcDir, "index.ts");

const GENERATED_HEADER =
  "// AUTO-GENERATED by packages/installed-plugins/scripts/generate-surface-registries.mjs. Do not edit manually.\n";

function escapeRegExp(value) {
  return value.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function descriptorImportToFile(importPath) {
  const match = importPath.match(/^@vivd\/([^/]+)\/descriptor$/);
  if (!match) {
    throw new Error(`Unsupported plugin descriptor import: ${importPath}`);
  }

  return path.join(repoRoot, "packages", match[1], "src", "descriptor.ts");
}

function readInstalledDescriptorImports(indexSource) {
  const imports = new Map();
  for (const match of indexSource.matchAll(
    /^import\s+\{\s*([A-Za-z0-9_]+)\s*\}\s+from\s+"([^"]+)";$/gm,
  )) {
    imports.set(match[1], match[2]);
  }

  const orderMatch = indexSource.match(
    /definePluginPackageInstallDescriptors\(\[\s*([\s\S]*?)\s*\]\s+as const\)/m,
  );
  if (!orderMatch) {
    throw new Error("Could not find installedPluginDescriptors array in src/index.ts");
  }

  const orderedSymbols = [
    ...orderMatch[1].matchAll(/\b([A-Za-z0-9_]+PluginDescriptor)\b/g),
  ].map((match) => match[1]);

  return orderedSymbols.map((symbol) => {
    const importPath = imports.get(symbol);
    if (!importPath) {
      throw new Error(`No import found for descriptor symbol ${symbol}`);
    }
    return { symbol, importPath };
  });
}

async function readSurfaceExports(descriptorPath) {
  const source = await readFile(descriptorPath, "utf8");
  const surfaceBlock = source.match(
    /surfaceExports:\s*\{\s*backend:\s*"([^"]+)",\s*frontend:\s*"([^"]+)",\s*cli:\s*"([^"]+)",\s*\}/m,
  );
  if (!surfaceBlock) {
    throw new Error(`Could not read surfaceExports from ${descriptorPath}`);
  }

  return {
    backend: surfaceBlock[1],
    frontend: surfaceBlock[2],
    cli: surfaceBlock[3],
  };
}

function buildRegistryFile({ surface, imports, body }) {
  return `${GENERATED_HEADER}${imports.join("\n")}\n\n${body.trim()}\n`;
}

function makeImportAlias(index) {
  return `installedPlugin${index}`;
}

function makeDescriptorArray(aliases) {
  return aliases.map((alias) => `  ${alias},`).join("\n");
}

const indexSource = await readFile(indexPath, "utf8");
const orderedDescriptorImports = readInstalledDescriptorImports(indexSource);

const installedPlugins = await Promise.all(
  orderedDescriptorImports.map(async ({ importPath }, index) => ({
    alias: makeImportAlias(index),
    surfaceExports: await readSurfaceExports(descriptorImportToFile(importPath)),
  })),
);

const backendImports = [
  'import { definePluginPackageDescriptors } from "@vivd/plugin-sdk";',
  ...installedPlugins.map(
    ({ alias, surfaceExports }) => `import ${alias} from "${surfaceExports.backend}";`,
  ),
];

await writeFile(
  path.join(srcDir, "backend.ts"),
  buildRegistryFile({
    surface: "backend",
    imports: backendImports,
    body: `
export const installedBackendPluginPackages = definePluginPackageDescriptors([
${makeDescriptorArray(installedPlugins.map(({ alias }) => alias))}
] as const);
`,
  }),
  "utf8",
);

const frontendImports = [
  'import {',
  '  buildSharedProjectPluginUiRegistry,',
  '  definePluginPackageDescriptors,',
  '} from "@vivd/plugin-sdk";',
  'import type { ComponentType } from "react";',
  'import type {',
  '  PluginPackageDescriptor,',
  '  SharedProjectPluginUiDefinition,',
  '} from "@vivd/plugin-sdk";',
  ...installedPlugins.map(
    ({ alias, surfaceExports }) => `import ${alias} from "${surfaceExports.frontend}";`,
  ),
];

await writeFile(
  path.join(srcDir, "frontend.ts"),
  buildRegistryFile({
    surface: "frontend",
    imports: frontendImports,
    body: `
interface InstalledFrontendPluginModule {
  pluginId: string;
  projectUi?: SharedProjectPluginUiDefinition & {
    ProjectPage?: ComponentType<{
      projectSlug: string;
      isEmbedded?: boolean;
    }>;
  };
}

type FrontendPluginPackage = PluginPackageDescriptor<
  string,
  InstalledFrontendPluginModule
>;

export const installedFrontendPluginDescriptors =
  definePluginPackageDescriptors([
${makeDescriptorArray(installedPlugins.map(({ alias }) => alias))}
  ] as const satisfies readonly FrontendPluginPackage[]);

export const installedFrontendSharedProjectPluginUiRegistry =
  buildSharedProjectPluginUiRegistry(installedFrontendPluginDescriptors);

export const installedFrontendPluginModules =
  installedFrontendPluginDescriptors.flatMap((descriptor) =>
    descriptor.frontend ? [descriptor.frontend] : [],
  );
`,
  }),
  "utf8",
);

const cliImports = [
  'import { definePluginPackageDescriptors } from "@vivd/plugin-sdk";',
  'import type { PluginPackageDescriptor } from "@vivd/plugin-sdk";',
  ...installedPlugins.map(
    ({ alias, surfaceExports }) => `import ${alias} from "${surfaceExports.cli}";`,
  ),
];

await writeFile(
  path.join(srcDir, "cli.ts"),
  buildRegistryFile({
    surface: "cli",
    imports: cliImports,
    body: `
type CliPluginPackage = PluginPackageDescriptor<string, unknown>;

export const installedCliPluginDescriptors = definePluginPackageDescriptors([
${makeDescriptorArray(installedPlugins.map(({ alias }) => alias))}
] as const satisfies readonly CliPluginPackage[]);
`,
  }),
  "utf8",
);
